from functools import lru_cache
from itertools import count
from sympy import prime, integer_log, primorial
from oeis_sequences.OEISsequences import bisection
def A133808(n):
    @lru_cache(maxsize=None)
    def g(x, m, j): return sum(g(x//(prime(m)**i), m-1, i) for i in range(1,min(j,integer_log(x, prime(m))[0])+1)) if m-1 else min(j,x.bit_length()-1)
    def f(x):
        c = n-1+x
        for k in count(1):
            if primorial(k)>x:
                break
            c -= g(x,k,integer_log(x,prime(k))[0])
        return c
    return bisection(f,n,n) # _Chai Wah Wu_, Mar 23 2026

